-- Seed: questions (ported from migration 002_seed-questions + reconciliations, extracted from ccl_tmp).
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
IF NOT EXISTS (SELECT 1 FROM dbo.questions)
BEGIN
  SET IDENTITY_INSERT dbo.questions ON;
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (1, 1, N'1. Responsibilities of the management body', N'Taking full responsibility for risk‑data quality and governance within the overall risk‑management framework
', 1, N'Governance', N'Page 5 enumeration 1', N'The Bank''s Management Body has either approved an Overarching BCBS 239 framework or an update to the DGF that: 
1. Defines adherence to BCBS 239 principles and the requirements of the RDARR Guide.
2. It provides sound governance arrangements, and ensures Management Body and Senior Management involvement throughout the RDARR processes, especially in governance and data quality monitoring through the Governance arrangements of the BoD and the relevant Committees.
3. Defines clear roles and responsibilities over the risk data aggregation and risk reporting processes.
4. Defines explicitly the scope of application with regards to material risks, material reports, KRIs, material subsidiaries and material models, considering the risk profile and complexity of the Bank.
5. Is reviewed and updated on a regular basis subject to the Bank''s relevant policy. 

The Bank''s Management Body is exercising responsibility through its regular Committees regarding the governance and data quality issues  as a part of the overall risk management framework.', N'There is no established RDARR Overarching Framework or update to the existing DGF that applies to the entire group or the framework has not been approved by the Management Body.', N'Only 2 out of 5 conditions need to be met to achieve the required level of compliance.', N'To achieve this level of compliance,4 out of 5 conditions must  be met regarding the framework and also the material exercise of the management body '' s responsibilities through its Committees. ', N'Moreover, to achieve this compliance level, all conditions must be met  regarding the framework and also  material exercise of the management body '' s responsibilities through its Committees. ', N'1) Data Governance Unit
2) Corporate Governance Division', N'1) Overarching BCBS 239 Framework (Policy and Regulations) 
2) Relevant Act. Committees Meeting Minutes .', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (2, 2, N'1. Responsibilities of the management body', N'Making RDARR a key priority for the institution and ensuring that adequate and sufficient material, financial and human resources are dedicated to it.
', 1, N'Governance', N'Page 6 enumeration 2. Part of paragraph: Making RDARR a key priority [..] key performance indicators for 
monitoring data quality. ', N'The Bank prioritizes the implementation and retention of its RDARR capabilities by ensuring that adequate and sufficient material, financial and human resources are dedicated to it. Units need to bring to the attention of the BCBS 239 Steering Committee any resource needs. ', N'There is no evidence of examining and considering needs (human resources, IT systems, advisory etc.) needed towards increasing compliance with the BCBS 239 principles.', N'There is evidence of examining and considering needs (human resources, IT systems, advisory etc.) needed towards increasing compliance with the BCBS 239 principles.', N'There is a systematic established process for addressing the relevant resource needs. Certain streams for covering resource needs are in progress.', N'There is evidence that the Bank has addressed the vast majority of relevant resource needs through a  systematic established process, ensuring adequate and sufficient material in both  financial and human recources. ', N'1) Data Governance Unit
2) Risk Function
3) Finance Function
4) Internal Control Function', N'1) RDARR program budget progress
2)  RDARR hires according to budget
3)  Consulting support according to budget', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (3, 3, N'1. Responsibilities of the management body', N'Approve and carry out the organization’s data governance framework by defining precise data‑quality standards—covering accuracy, integrity, completeness, and timeliness under both normal and stressed conditions—and by establishing detailed performance indicators to continuously monitor data quality
', 1, N'Governance', N'Page 6 enumeration 2. Part of paragraph: Making RDARR a key priority [..] key performance indicators for 
monitoring data quality. ', N'The institution has established a data governance framework which meets RDARR requirements and:
1. Has been approved by the Management Body.
2. Mandates the set up of key quality indicators for monitoring data quality.
3. Is applicable to all BCBS 239 material legal entities.', N'The institution lacks a formal data governance framework. ', N'The established DG Framework has been approved by the Management Body. Basic requirements for data quality, such as accuracy and timeliness, are defined, but integrity and completeness during normal and stress periods are not fully addressed. Preliminary KPIs for monitoring data quality exist but lack granularity and effective tracking mechanisms.', N'The institution has a well-defined data governance framework that covers most aspects of data quality, including accuracy, integrity, completeness, and timeliness in normal and stress periods. Detailed KPIs for monitoring data quality are in place for critical areas, but some gaps remain in achieving comprehensive coverage and consistent application across all business functions', N'The institution has approved and fully implemented a robust data governance framework. Detailed requirements for data quality are established, addressing accuracy, integrity, completeness, and timeliness comprehensively for both normal and stress periods. Comprehensive and actionable KPIs are in place to monitor data quality across all business functions, ensuring effective oversight and continuous improvement.', N'Data Governance Unit', N'Data Governance Framework', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (4, 4, N'1. Responsibilities of the management body', N'Overseeing and prioritizing key deliverables within agreed timelines while monitoring progress and evaluating RDARR capabilities against BCBS 239 best practices

', 1, N'Governance', N'Page 6 enumeration 3', N'The Bank has developed a comprehensive RDARR implementation Programme which is subject to oversight, prioritization and monitoring of key deliverables within the agreed timelines as communicated to the supervisory authorities taking into consideration supervisory expectations and market leading practices. ', N'The institution''s own view in terms of adherence to the BCBS 239 principles and the assessment procedure has not been established.', N'
The Bank has established a comprehensive overarching BCBS 239 Framework, including definition of compliance with RDARR and BCSB 239 requirements, and has an on-going RDARR implementation programme with a roamap to achieve full compliance within the agreed timelines with supervisory authorities. However, the programme is not comprehensive (e.g. prioritisation, roles and responsibilities, missing detailed remediation plan, key milestones, scope, dependencies) and its progress is not regularly monitored by the Management Body through a structured monitoring mechanism. The assessment of RDARR capabilities in relation to the best practices described in the BCBS 239 principles has not been established.', N' The Bank''s RDARR implementation programme is largely comprehensive with a documented credible roadmap covering the full scope of remedation actions, including a prioritisation matrix, key pillars, dependencies, risks and clear roles and responsibilities. Programme oversight is established and functional (e.g., regular  Committees, governance forums, escalation and issue management defined). The assessment of RDARR capabilities in relation to the best practices described in the BCBS 239 principles has been established, performed and communicated to the Management Body but not on a regular basis.', N'The Bank''s RDARR implementation programme is fully comprehensive and aligned to RDARR guide and BCBS 239 requirements, supervisory expectations, and leading market practices. A fully risk-aligned prioritization framework is established driving sequencing of deliverables and resource allocation. Regular monitoring and reporting mechanism to the Management Body is established (e.g., KPIs, RAG statuses), with relevant insightfull presentations and evidence of timely management actions. The assessment of RDARR capabilities in relation to the best practices described in the BCBS 239 principles as been established  is performed and communicated to the Management Body on a regular basis.', N'Data Governance Unit', N'1)RDARR Overarching Policy and approval
2) Implementation Programm aproovals
3) Meeting Minutes from relevant Committees and presentations', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (5, 5, N'1. Responsibilities of the management body', N'Define the institution’s interpretation of BCBS 239 compliance while recognizing any technical or legal constraints that may limit full risk data aggregation', 1, N'Governance', N'Page 6 enumeration 3', N'a) The Bank''s Management Body has defined what it means to adhere to BCBS 239 principles considering the nature, scale and complexity of the institution''s operations risk profile
(b) Sets a target state / minimum threshold for the level of compliance with the principles, acknowledging potential technical, business and legal limitations that might prevent full development of RDARR capabilities.
(c) Assesses RDARR capabilities in relation to the best practices described in the BCBS 239 principles.
(d) Defines different levels of compliance based on an expected target state.
(e)  Provides a compliance assessment result, which is comprehensive and comparable period over period. 
(f) Requires the compliance assessment results to be presented and discussed at Management Body Level which has the ultimate responsibility
(g) Requires the Institution''s implementation program to increase the level of compliance towards the set target', N'The institution''s own view in terms of adherence to the BCBS 239 principles and the assessment procedure has not been established.', N'
The institution has established an own view that meets at least 3 out of 7 conditions.', N'The established view of the institution meets at least 4 out of 7 conditions .', N'The established view of the institution meets all conditions.', N'Data Governance Unit', N'RDARR Overaching Policy and approval', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (6, 6, N'1. Responsibilities of the management body', N'Assign designated senior leaders to oversee implementation of the data governance and RDARR framework, while ensuring that the management body retains full accountability and that clear roles and responsibilities are established across the organisation', 1, N'Governance', N'Page 6 enumeration 4. Part of paragraph: Selecting one or two members of the management body […] for ensuring implementation of the data governance framework in the institution.

Page 6 enumeration 5', N'The Bank has established sound governance arrangements for the monitoring of the framework''s implementation. In particular:
1. It sets clear roles and responsibilities for the end - to - end RDARR processes.
2. It has delegated the authority to one or two single individuals either from the management function of its Management Body and/or from its Senior Management with direct reporting line to the Management Body, to exercise responsibility for the implementation of the BCBS 239 and data governance frameworks ', N'No Overarching BCBS 239 framework has been established.', N'The Bank has established an Overarching BCBS 239 framework, as well as governance arrangements for the monitoring of the framework''s implementation. However, roles and responsibilites of involved stakeholders established in the framework, only partially cover end-to-end RDARR procesess, while no Management Body member delegate has been determined.', N'The Bank has established an Overarching BCBS 239 framework and sound governance arrangements for the monitoring of the framework''s implementation cover roles and responsibilites of involved stakeholders to a large extend.No Management Body member delegate has been determined.', N'The Bank has established an Overarching BCBS 239 framework and governance arrangements for the monitoring of the framework''s implementation which clearly cover roles and responsibilites of involved stakeholder across the full spectrum of RDARR processes. Management Body member delegate has been determined.', N'Data Governance Unit', N'RDARR Overaching Policy and approval', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (7, 7, N'1. Responsibilities of the management body', N'Ensuring Group‑level RDARR policies and processes are implemented, with subsidiaries responsible for applying them locally
', 1, N'Governance', N'Page 6 enumeration 6', N'The Bank''s  Management Body has established a process to ensure: 
1. The roll - out and implementation of relevant frameworks and policies for RDARR at the Group level (material legal entities).
2. Responsibility for implementing the group-wide frameworks, policies, and processes at the material legal entity level is assumed by the subsidiaries'' Management Bodies.', N'Relevant RDARR frameworks and policies have neither been established nor yet approved by the Management Body of each material legal entity. ', N'Some but not all relevant RDARR frameworks and policies have been  approved by the Management Body of each material legal entity.', N'All relevant RDARR frameworks and policies have been established and approved by the Management Body of each material legal entity, however there are no appropriate mechanisms in place for the implementation of the relevant frameworks in each material legal entity. ', N'All relevant RDARR frameworks and policies have been approved by the Management Bodies of all material legal entities and there are appropriate mechanisms in place for the implementation of the relevant frameworks in each material legal entity.', N'1) Data Governance Unit (Bank)
2) Data Governance Unit of each MLE
3) Corporate Governance Division of each MLE', N'1) Material entities Frameworks and approvals
2) Material Entities Implementation Programms
3) Material Entities presentations to the Management Body and relevant meeting minutes.', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (8, 8, N'1. Responsibilities of the management body', N'Regularly ensuring that internal risk reports provide a balanced mix of qualitative and quantitative insights that support effective decision‑making
', 1, N'Governance', N'Page 6 enumeration 7', N'The Bank has established a feedback loop mechanism for the Management Body to ensure the meaningfulness of the internal risk reports in terms of qualitative and quantitative information and their contribution to sound decision making. ', N'No feedback loop mechanism for the Management Body for internal risk reports has been established.', N'The feedback loop mechanism for the Management Body regarding internal risk reports is established, however is performed on an ad hoc basis.', N'The mechanism for internal risk reports is performed on  a regular basis. Rarely  proposals or changes are registered through time as part of the process.  ', N'The mechanism for internal risk reports is performed on  a regular basis.  The relevant committees propose a few  improvements or changes and  the corresponding responsibilities are assigned accordingly .', N'Risk & Finance Reporting framework owners', N'Evidence from report recipient''s feedback process', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (9, 9, N'1. Responsibilities of the management body', N'Regularly track data‑quality KPIs and ensure action plans address major issues, while overseeing strong processes and controls that maintain data quality', 1, N'Governance', N'Page 6 enumeration 8', N'A Data Quality monitoring mechanism is established, which encompasses, but is not limited to, the following:
a) Defined roles, responsibilities and minimum standards related to DQ.
b) A process for monitoring the key performance indicators used for reporting on DQ.
c) Escalation processes and other procedures for examining, addressing and remediating (mitigating) DQ issues.', N'There is no established Data Quality (DQ) monitoring mechanism in place.', N'A Data Quality (DQ) monitoring mechanism has been established, which meets only 1 out of 3 conditions.', N'A Data Quality (DQ) monitoring mechanism meets 2 out of 3 conditions.', N'A Data Quality (DQ) monitoring mechanism meets all 3 conditions.', N'Data Governance Unit', N'1) RDARR Overarching Policy
2) Data Quality policies or regulations
3) Presentations of DQIs to the Management Body an meeting minutes
4) Escalated issues in presentations and meeting minutes', N'1. Data Quality Indicators success ratio: (Number of successful data quality indicators ÷ Total data quality indicators) x 100                               2. RAF RDARR indicators success ratio: (Number of successful RAF RDARR indicators ÷ Total RAF RDARR indicators) x 100 ', NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (10, 10, N'1. Responsibilities of the management body', N'Ensure that members of the management body and heads of control functions have strong and up‑to‑date knowledge of data management, IT, financial and non‑financial risks (including climate and security risks), along with the related data and reporting requirements. Their skills and experience in these areas should be considered when assessing collective suitability and reviewed regularly. Ongoing training should be provided so they can effectively understand, assess, and oversee the institution’s key risks and operational impacts.', 1, N'Governance', N'Page 7 enumeration 9

Page 7 enumeration 10

Page 7 enumeration 11', N'The institution has established a formal process which consists of:
i) An assessment cycle of the collective suitability of Management Body members which takes into account the knowledge, skills and experience of members relating to data management, IT and financial and non - financial risks, as well as the related data and reporting requirements which is reviewed on an annual basis and might result to specific recommendations and targeted actions.  
ii) An RDARR Awareness Programme addressed to Management Body and Senior Management members including members in order to ensure that their knowledge, skills and experience remain up to date and they possess deep understanding of data management, IT, and reporting requirements. ', N'The Bank has established a formal process for the assessment of collective suitability of Management Body members  however it does not take specifically into account the knowledge, skills and experience of members  relating to data management, IT and financial and non - financial risks, as well as the related data and reporting requirements.', N'The Bank has established a formal process for the assessment of collective suitability of Management Body members  which takes into account the knowledge, skills and experience of members relating to data management, IT and financial and non - financial risks, as well as the related data and reporting requirements which however results to no actions.  Training to to Management Body and Senior Management members is performed in a limited and non regular basis.', N'The Bank has established a formal process for the assessment cycle of the collective suitability of Management Body members which takes into account the requirements set in the condition (i) and result to specific recommendations and targeted actions.  
However, the RDARR Awareness Programme has been designed but either has not been established or is not effective in ensuring the requirements set in condition (ii).', N'The Bank has fully established a formal process for the assessment cycle of the collective suitability of Management Body members which takes into account the requirements set in the condition (i) and result to specific recommendations and targeted actions.  
The Bank has established a RDARR Awareness Programme and has streamlined the implementation of other initiatives towards increasing the relevant skills and knowledge meeting also condition (ii).', N'Data Governance Unit', N'1) Managemt body RDARR related skills
2) Awareness and training programms', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (11, 11, N'2. Sufficient scope of application', N'The bank must establish a comprehensive data governance framework that supports effective risk identification, management, monitoring, and reporting. This framework should apply across all material legal entities, business lines, risks, and reporting processes, covering the entire data lifecycle—from origination to reporting. It should be fully integrated into existing governance structures and ensure robust, group‑wide processes and controls for maintaining data quality. The framework must clearly define its scope, including the reports, models, and risk indicators it covers, using proportionate and measurable criteria aligned with the institution’s size, complexity, and risk profile. It should also encompass all material risks and risk concentrations identified by the institution.', 1, N'Governance', N'Page 7. 1st Paragraph

Page 7. 2nd Paragraph

Page 8. 1st Paragraph', N'The Bank has developed and implemented a comprehensive process with regards to the scoping of material legal entities for BCBS 239 which is proportionate to the risk profile as well as complexity and scale of the Bank''s operations and is based on clear, measurable and proportionate criteria which results to a sufficient scope of application and enables the Bank to implement its DGF and/or Overarching BCBS 239 Framework at Group level. 
', N'No scoping process for the identification of MLEs has been established by the Bank.', N'The Bank has established a process for the identification of MLEs however this process is not based on clear and proportionate criteria and thus it cannot be concluded whether it results to a sufficient coverage at Group level. ', N'The Bank has established a sound process for the identification of MLEs which is based on a set of well defined, clear and proportionate criteria which results to  a sufficient coverage at Group level. However, this process has not yet been implemented in order to enable the roll - out of the Data Governance Framework of the Bank at Group level.  ', N'All expectations are met. ', N'Data Governance Unit', N'1) RDARR Overarching  Policy 
2) Legal entities materiality assessment process documentation and calculation', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (12, 12, N'2. Sufficient scope of application', N'The data governance framework should cover all major report types: key internal risk reports used for decision‑making, externally published financial reports including annual statements, and all supervisory reports submitted to regulators such as FINREP/COREP, stress‑test submissions, and Pillar 3 disclosures', 1, N'Governance', N'Page 8 enumeration 1', N'The Bank has developed and implemented a comprehensive process with regards to the scoping of material reports for BCBS 239 which is proportionate to the risk profile as well as complexity and scale of the Bank''s operations and covers the  following:
a) Internal risk reports used in decision-making and steering processes. This includes reports that provide information on risk appetite indicators (metrics and limits) as well as the main overall risk reports and main risk reports per material risk type (financial and non-financial).
b) Financial reports that are externally published as well as annual financial statements.
c) Supervisory reports that are submitted to financial supervisory or regulatory authorities. This includes at least FINREP/COREP reporting templates including the Short Term Exercise, submissions to EU-wide EBA stress tests and Pillar 3 disclosures.', N'The scope of material reports in scope of BCBS 239 is not captured in the Overarching BCBS 239 Framework.', N'The list of material risk reports specified based on the scope of application described within the Overarching BCBS 239 Framework does not cover all 3 different types of reports described in the ECB Guide.', N'The list of material risk reports specified based on the scope of application described within the Overarching BCBS 239 Framework covers the 3 different types of reports, but does not cover the entire perimeter prescribed by the Guide. ', N'The list of material risk reports specified based on the scope of application described within the Overarching BCBS 239 Framework covers the vast majority prescribed by the Guide, considering also the dimensions of complexity and proportionality.', N'1) Data Governance Unit
2) Risk Function (data owner)
3) Finance Function (data owner)', N'1) RDARR Overarching  Policy 
2) Risk Reports materiality assessment process documentation and calculation', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (13, 13, N'2. Sufficient scope of application', N'The data governance framework should cover all key internal risk‑management models, including Pillar 1 regulatory capital models, Pillar 2 risk and capital models, and other major models like IFRS 9 provisioning and value‑at‑risk. It should encompass both the input data used to develop these models and the critical outputs they produce for managing the institution’s risks', 1, N'Governance', N'Page 8 enumeration 2', N'The Bank has developed and implemented a comprehensive process with regards to the scoping of material models for BCBS 239 which is proportionate to the risk profile as well as complexity and scale of the Bank''s operations. 
The scope is consistent with the existing MRM policy of the Bank and includes key internal risk management models including, but not limited to, Pillar 1 regulatory capital models (such as internal ratings-based (IRB) approaches for credit risk), Pillar 2 risk and capital models and other key risk management models (such as IFRS9 collective provisions models and value-at-risk models). This includes input data for model development as well as resulting model outputs (e.g. exposure at default, probability of default or loss-give-default estimates) that are crucial for managing the risks faced by the institution.
', N'The Bank does not maintain a well-structured and comprehensive inventory of all models. In addition, the scope of material risk models is not defined, since the Bank has not established a formal process for their materiality assessment.', N'The Bank maintains a well-structured and comprehensive inventory of models and has established a formal process for model materiality assessment, based on the Model Risk assessment process performed by MVU, resulting to a final list of material models, however, the final list of scope models does not include all the key risk management models prescribed by RDARR requirements.', N'The Bank maintains a well-structured and comprehensive inventory of models and has  defined the scope of material risk models, in line with RDARR guide requirements, but it is not captured within the Overarching BCBS 239 Framework.', N'The Bank maintains a well-structured and comprehensive inventory of models and has  defined the scope of material risk models, in line with RDARR guide requirements and it is  captured within the Overarching BCBS 239 Framework.', N'1) Data Governance Unit
2) Risk Function (data owner)', N'1) RDARR Overarching  Policy 
2) Risk Reports materiality assessment process documentation and calculation', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (14, 14, N'2. Sufficient scope of application', N'The data governance framework should include the institution’s risk appetite indicators and other key risk indicators used in internal risk, financial, and supervisory reports and models. These indicators must be defined based on the institution’s risk profile, and the critical data elements that support them should be clearly identified
', 1, N'Governance', N'Page 8 enumeration 3
', N'The Bank has developed and implemented a comprehensive process with regards to the scoping of KRIS for BCBS 239 purposes.
 
In particular, key risk indicators, the scope of application includes at least the Bank''s quantitative risk appetite indicators as well as other key risk indicators referred to in the internal risk, financial and supervisory reports and models described above. The scope of key risk indicators reflects the risk profile of the Bank as well as the scale and complexity of its operations. In this regard, the critical data elements underlying the key risk indicators are also explicitly identified and documented. ', N'The bank has not defined the scope of material risks for the purposes of RDARR, based on a robust process for risk identification and materiality assessment (RIMA process).', N'The Bank has designed and implemented a robust process for risk identification and materiality assessment (RIMA process). However, the Bank has not explicitly defined the scope of material risks for RDARR purposes. Identified KRIs do not cover all quantitative risk indicators within the Bank''s Risk Appetite Statements, defined within its Risk Appetite Dashboard.', N'1. The Bank has not explicitly defined the scope of material risks  for the purposes of RDARR by leveraging upon the results (i.e. risks identified as material) in the context of the RIMA process.
2. KRIs are identified within the Risk Appetite Dashboard (section within RAF) covering all quantitative risk indicators within the Bank''s Risk Appetite Statements. However, the indicators deemed material for RDARR purposes remain unspecified.
3. There is no established process for the identification of critical data elements within the Bank, by mapping of CDEs with KRIs.', N'1. The Bank has explicitly defined the scope of material risks the for the purposes of RDARR by leveraging upon the results (i.e. risks identified as material) in the context of the RIMA process.
2. The scope of KRIs deemed material for RDARR purposes has been specified, on the basis of the Risk Appetite Dashboard (as defined in RAF) by including within the scope all quantitative Risk Appetite Statements.
3.The Bank has established a process for the identification of critical data elements within the Bank, by mapping of CDEs with KRIs.
4. All the above are adequately captured within the Overarching BCBS 239 Framework', N'1) Data Governance Unit
2) Risk Function (data owner)
3) Finance Function (data owner)', N'1) RDARR Overarching  Policy 
2) RCDEs,Reports , KRIs materiality assessment process documentation and calculation
3) Percentage of total perimeter'' s completion ', N'1. Data Owners assigned to CDEs: (Number of CDEs with assigned Data Owners ÷ Total CDEs) x 100                2. CDEs explicitly documented: (Number of CDEs explicitly documented ÷ Total CDEs) x 100 ', N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (15, 15, N'3. Effective data governance framework', N'Data owners are accountable for key risk indicators and critical data elements across the full data lifecycle. Their responsibilities include defining data‑quality controls with data users, ensuring data accuracy, integrity, completeness, and timeliness, monitoring and reporting data quality, driving remediation when issues arise, and managing metadata such as data lineage and the data dictionary', 1, N'Governance', N'Page 9 enumeration 1', N'The Bank has delegated to data owners the responsibility for data used in the calculation of key risk indicators and critical data elements throughout the complete aggregation process (front to end). The responsibilities include:
a) Contributing, in alignment with data users, to the definition of data quality controls and the classification of key risk indicators and critical data elements;
b) Ensuring the accuracy, integrity, completeness, and timeliness of data;
c) Ensuring the monitoring and reporting of data quality through data quality processes;
d) Ensuring the remediation of insufficient data quality;
e) Managing metadata relating to data lineage and the data dictionary.', N'The Bank has assigned responsibility to data owners for only one of the dimensions (a) to (e).', N'The Bank has assigned responsibility to data owners for only 2 of the dimensions (a) to (e).', N'The Bank has assigned responsibility to data owners for at least  3 of the dimensions (a) to (e).', N'The Bank has assigned responsibility to data owners for all of the dimensions (a) to (e).', N'Data Governance Unit', N'1) Data Governance Framework.
2) Assigned Data Owners List and Domains. 
3) CDEs List and relevant metadata.', N'RAF RDARR indicators success ratio: (Number of successful RAF RDARR indicators ÷ Total RAF RDARR indicators) x 100 ', NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (16, 16, N'3. Effective data governance framework', N'A central data governance function is responsible for setting data‑quality policies and processes, overseeing the organisation‑wide implementation of the data governance framework, evaluating and monitoring data quality, and participating in major change‑management initiatives that affect RDARR—such as mergers, acquisitions, outsourcing, new products, and significant IT changes', 1, N'Governance', N'Page 9 enumeration 2', N'The Data Governance Unit (DGU) is responsible for:
1) issuing policies and processes for data quality management,
2) ensuring the correct implementation of the Data Governance Framework (DGF) at Group level, 
3) evaluating and monitoring data quality, and 
4) participating in change management activities that significantly affect RDARR. These activities may include mergers or acquisitions of material legal entities, outsourcing functions to third parties, introducing new products, launching new tools, upgrading existing tools, and other IT change initiatives.', N'None of the conditions are met.', N'To achieve the required level of compliance, 1 out of 4 conditions must be met.', N'To achieve the required level of compliance, 3 out of 4 conditions must be met.', N'To achieve the required level of compliance, all conditions must be met.', N'Data Governance Unit', N'1) Policies. 
2)DQIs and monitoring evidence. 
3) Proof of participation in change management projects (designated person, comments, etc).', N'KQI for evaluating Data Quality per Domain: (Number of KQIs defined for data quality ÷ Total CDEs per domain) x 100 ', NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (17, 17, N'3. Effective data governance framework', N'An independent second‑line validation function must ensure that RDARR processes operate effectively. It should remain organisationally separate from data governance and RDARR units—or apply safeguards and segregation of duties if housed in the same function—to avoid conflicts of interest. The validation function should regularly assess RDARR capabilities across all material entities and risk types, covering all components such as IT infrastructure, data lineage, taxonomy, outsourced activities, IT changes, mergers, acquisitions, and new product launches. It must also be supported by adequate staff and strong expertise in IT, data and reporting', 1, N'Governance', N'Page 9-10 enumeration 3. Part of paragraph: A validation function within the second line of defence that is independent […] as well as the complexity of 
the risks inherent in its business model.', N'Governance arrangements over IVU

 An Independent Validation Unit (IVU) is established and fulfills the following criteria:
1. It is independent from the units involved in data governance and end to end RDARR processes. 
2. It forms an integral part of the second line of defense (2nd LoD) ensuring that the Bank''s RDARR processes are functioning as intended.   
3. It is subject to sound governance arrangements monitoring its independence with well defined roles and responsibilities.  

Validation activities

The Independent Validation Unit (IVU) has established a validation framework which describes its scope of work and validation activities based on which:
1. Regular assessments of the Institution''s RDARR capabilities are performed covering all material legal entities and risk types. On the basis of the nature, size and scale of its operations the validation work with regards to material subsidiaries can either be performed at a Group or local subsidiary level ensuring compliance and consistency across the Group.
2. The scope of work of the IVU covers all components of the end - to - end RDARR processes (e.g. IT infrastructure, data lineage and data taxonomy). 
3. Presents the annual validation plan and validation report and findings to the Board Risk Committee (BRC), for the latter to escalate significant findings to the BoD accordingly.
4. In order to cope successfully with its responsibilities the validation It is equipped with adequate and sufficient human resources and relevant IT, data and reporting expertise.
5. In addition the scope of work includes the oversight of outsourced functions, IT change initiatives, mergers and acquisitions and new product launches.', N'There is no established IVU in place or it is not independent.', N'An IVU has been established and satisfies only 1 out of 3 conditions regarding governance arrangements and points 1 and 2 with regards to validation activities.', N'An IVU has been established and satisfies 2 out of 3 conditions regarding governance arrangements requirements and points 1 to 3 with regards to validation activities.', N'An IVU has been established and satisfies all conditions regarding both governance arrangements requirements and validation activities.', N'RDARR Validation Unit', N'1) Annual Validation Reports  and Thematic Reviews. 
2) Staff CVs and Expertise. 
3) List of tools used and permissions. 
4) Evidence of participation in New initiatives, merges  projects and new products.', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (18, 18, N'4. Integrated data architecture', N'The Group should implement an integrated data architecture that includes comprehensive data taxonomies—such as a business definitions dictionary and a metadata repository—covering all material entities, business lines, risks, reports, key risk indicators, critical data elements, and relevant models. Managing these taxonomies requires maintaining consistent, uniform data definitions and glossaries with clearly assigned ownership', 2, N'Data Architecture & IT Infrastructure', N'Page 10-11. Part of paragraph: To ensure the quality of the data used for risk, supervisory and financial reporting […]  identified as being within the scope 
of application (see point 3 of Section 3.2).', N'The Bank needs to establish an integrated data architecture that is implemented at the group level, and includes data taxonomies for the scope of application. More specifically: 
1. develop and maintain a dictionary of uniform main business definitions and the attributed respective data ownership;
2. develop and maintain a metadata repository that covers the scope of application as defined by the Bank.', N'The Bank has no formal data architecture or integrated taxonomies in place. Data definitions and glossaries are inconsistent or absent, leading to significant inefficiencies and compliance gaps across the Group.', N'The Bank has initiated efforts to design a data architecture, but integrated taxonomies remain incomplete or inconsistently applied. Some data glossaries and definitions exist, but they are siloed and not uniformly adopted across the Group.', N'The Bank has established a partially implemented data architecture with integrated taxonomies that cover most critical areas. Data glossaries and definitions are present and largely consistent, but some gaps or inconsistencies remain in Group-wide application.', N'The Bank has designed and implemented a robust data architecture with integrated taxonomies including uniform data glossaries and data definitions across the Group.', N'Data Governance Unit', N'Access in Data Dictionary and metadata repository for data definitions.', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (19, 19, N'4. Integrated data architecture', N'The group‑wide integrated data architecture must include data taxonomies—such as a business definitions dictionary and a metadata repository—covering all key entities, risks, reports, indicators, and models. Managing these taxonomies requires establishing validation rules that specify permitted values or acceptable ranges for the data', 2, N'Data Architecture & IT Infrastructure', N'Page 10-11. Part of paragraph: To ensure the quality of the data used for risk, supervisory and financial reporting […]  identified as being within the scope 
of application (see point 3 of Section 3.2).', N'The Bank needs to establish an integrated data architecture that is implemented at the group level, and includes data taxonomies for the scope of application. More specifically, validation rules allowing specific values or a range of values should be established for critical data elements and KRIs within the scope of application, as defined by the Bank.
', N'Validation rules for specific or range values are absent, leading to inconsistent data use across the Group.', N'Validation rules for specific or range values are partially defined but are not uniformly applied across material entities and risks.', N'Validation rules for specific or range values are defined and applied for key areas, but gaps remain in achieving full alignment and comprehensive Group-wide application.', N'Robust validation rules are implemented, allowing specific or a range of values, ensuring consistency and reliability across all Group entities and processes.', N'1) Risk Function
2) Finance Function
3) Data Governance Unit
4) IT', N'Assess validation rules list or Registry or via access to relevant system.', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (20, 20, N'4. Integrated data architecture', N'The group‑wide integrated data architecture must include comprehensive data taxonomies covering all key entities, risks, reports, indicators, and models. Managing these taxonomies requires maintaining complete, up‑to‑date data lineage at the data‑attribute level—from initial data capture through all extraction, transformation, and loading steps—for all risk indicators and their critical data elements within scope', 2, N'Data Architecture & IT Infrastructure', N'Page 10-11. Part of paragraph: To ensure the quality of the data used for risk, supervisory and financial reporting […]  identified as being within the scope 
of application (see point 3 of Section 3.2).', N'The Bank needs to establish an integrated data architecture that is implemented at the group level, and includes data taxonomies for the scope of application. More specifically, the institution should maintain up-to-date data lineages on data attribute level (starting from data capture and including extraction, transformation and loading) for the risk indicators, and their critical data elements, identified as being within the scope of application.', N'The Bank lacks documented data lineage, and there is no evidence of traceability for material KRIs. Data flows between systems are poorly understood, creating significant risks to reporting accuracy and consistency', N'The Bank has initiated documentation of data lineage, but coverage is incomplete and primarily limited to critical systems or specific business units. ', N'The Bank has established a comprehensive data lineage framework covering most material KRIs. Evidence of data lineage exists across critical systems, but gaps remain in achieving end-to-end traceability for the complete data lifecycle at the Group level', N'Evidence of data lineage at attribute level exists covering the end to end data lifecycle (front systems to reporting layer) for the all material KRIs at Group level.', N'Data Governance Unit of each MLE', N'1)Access in Data Dictionary and metadata repository for data lineage.', N'Data Lineage on CDEs: (Number of CDEs with lineage ÷ Total CDEs) x 100 ', NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (21, 21, N'5. Group-wide data quality management and standards', N'Institutions should establish group‑wide policies within the risk management or data governance framework to ensure strong data‑quality controls, timely remediation of issues, and transparency around limitations and data‑quality risks. These policies must include data‑quality checks—covering accuracy, integrity, completeness and timeliness—across the entire data flow from source systems to reporting, with automation where appropriate, and periodic reconciliation with internal accounting/finance data, external sources, and model‑development datasets', NULL, N'Accuracy and Integrity | Completeness | Timeliness', N'Page 11 enumeration 1. Part of paragraph: The implementation of data quality controls (covering, at least, the dimensions 
of accuracy and integrity, completeness and timeliness) […] and related model development data.', N'The Group''s frameworks encompass through policies and processes the implementation of data quality controls that:
1. Cover the dimensions of accuracy, integrity, completeness and timeliness, as applicable. 
2. Cover the data aggregation process from front office systems (and other capture systems) to the reporting layer for all critical data elements in the scope of BCBS 239.
3. Are automated, where appropriate.', N'The Bank''s frameworks, policies and processes do not include provisions for the implementation of data quality controls covering any of the three (3) mentioned expectations.', N'The Bank''s frameworks, policies and processes include provisions for the implementation of data quality controls covering partially the conditions mentioned.', N'The Bank''s frameworks, policies and processes include provisions for the implementation of data quality controls covering largely the mentioned conditions.

In addition, Data Quality controls are implemented throughout the main nodes of the data aggregation process for the scope of application.', N'The Bank''s frameworks, policies and processes include provisions for the implementation of data quality controls covering all the mentioned conditions for the scope of application. 

Data Quality controls are implemented and automated, as appropriate, throughout the data aggregation process.', N'1) Risk Function
2) Finance Function
3) IT', N'1)Access to data Quality Controls Repository.
2) Data Quality Remediations implemneted and results.', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (22, 22, N'5. Group-wide data quality management and standards', N'Group‑wide policies should define and measure data‑quality indicators—covering accuracy, integrity, completeness, and timeliness—and set tolerance levels and correction procedures. They should also document clear operational processes for handling any breaches of these data‑quality standards', NULL, N'Accuracy and Integrity | Completeness | Timeliness', N'Page 11 enumeration 2. Part of paragraph: The definition and measurement of data quality indicators covering, at least, the 
dimensions of accuracy and integrity […]  on risk measurement effectiveness and the risk profile of the 
institution (see Section 3.1). ', N'The Data Governance Framework encompasses through policies and processes the scope of application and the definition and measurement of data quality indicators that:
1. Cover the dimensions of accuracy and integrity, completeness,
2. Cover the dimension of timeliness,
3. Include tolerance levels for data quality indicators.
4. Document operational processes in case of breaches,', N'None of the 4 conditions are prescribed in DGF policies and processes.', N'All conditions are prescribed in DGF policies and processes but not implemented on the CDEs within the scope of application.', N'All conditions are prescribed in DGF policies and processes and their implementation covers the majority of CDEs within the scope of application.', N'All conditions are prescribed in DGF policies and processes and their implementation covers the CDEs within the scope of application. Any excluded CDEs are justified.', N'Data Governance Unit', N'1) Access to DQI Inventory
2) Percentage of completion per total targeted perimeter.', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (23, 23, N'5. Group-wide data quality management and standards', N'Data quality indicators should allow for the systematic monitoring and recording of the quality of the related data covering the entire lifecycle of the data.', NULL, N'Accuracy and Integrity | Completeness | Timeliness', N'Page 11 enumeration 2. Part of paragraph: The definition and measurement of data quality indicators covering, at least, the 
dimensions of accuracy and integrity […]  on risk measurement effectiveness and the risk profile of the 
institution (see Section 3.1). ', N'The Bank has established a coherent set of data quality indicators within its Data Governance Framework and related processes which exhibit at least the following attributes:
1. Allow for the systematic monitoring of data quality on an on – going basis;
2. Enable the systematic recording, by keeping detailed documentation of assessments, issues identified and action logs;
3. The DQIs should cover the entire data lifecycle.', N'There are no defined processes for DQIs in the DGF.', N'The defined processes for DQIs meet only 1 out of 3 conditions.', N'The defined processes for DQIs meet 2 out of 3 conditions.', N'The defined processes for DQIs meet all conditions.', N'1) Data Governance Unit
2) Risk Function
3) Finance Function', N'1)Data Governance Framework
2) Acess to DQI inventory
3) Percentage of completion per total targeted perimeter.', N'1. Data Quality Indicators success ratio: (Number of successful data quality indicators ÷ Total data quality indicators) x 100                               2. RAF RDARR indicators success ratio: (Number of successful RAF RDARR indicators ÷ Total RAF RDARR indicators)                 3. KQI for evaluating Data Quality per Domain: (Number of KQIs defined for data quality ÷ Total CDEs per domain) x 100 ', N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (24, 24, N'5. Group-wide data quality management and standards', N'Group‑wide policies should maintain a complete, up‑to‑date register of all data‑quality issues and limitations. This register must document the severity and root causes of issues, quantify their impact on affected risk and business areas, define clear responsibilities and escalation paths, set remediation deadlines, and record the final resolution date with supporting evidence', 3, N'Accuracy and Integrity', N'Page 11 enumeration 3', N'The Data Governance Framework sets the group-wide policies and processes that include an up-to-date and complete overview ("register") of data quality issues and limitations, including:
(i) an assessment of the severity of these issues, 
(ii) a root cause analysis, 
(iii) a quantitative impact analysis of material/severe data errors on the risk and business areas affected, 
(iv) clearly defined processes and responsibilities for remediating and escalating data quality issues, depending on the materiality of the issues,
(v) target deadlines for remediation, and 
(vi) actual remediation closure dates (including appropriate evidence).', N'There is no group-wide policies and processes for a registry of data quality issues and limitations.', N'There is a policy for registering the DQ issues, that is not applicable at a Group-level or it does not cover more than 2 of the 6 conditions.', N'There is a group-wide policy for registering the DQ issues, which covers 3 or 4 out of 6 conditions.', N'There is a group-wide policy for registering the DQ issues, which covers at least 5 conditions.', N'Data Governance Unit', N'1) Access to the Data quality registry
2) Relevant minutes of Committees and remediations results 
3) Data quality remediations data in specific sample areas (upon request).', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (25, 25, N'5. Group-wide data quality management and standards', N'Group-wide policies and processes should include periodical reconciliation with institutions’ sources and reports (in the areas of accounting and finance and with external sources used) and related model development data.', 3, N'Accuracy and Integrity', N'Page 11 enumeration 1. Part of paragraph: The implementation of data quality controls (covering, at least, the dimensions 
of accuracy and integrity, completeness and timeliness) […] and related model development data.', N'
The Group has established an Overarching Risk Reporting Framework that:
1. Mandates the existence of a reconciliation process of material reports.
2. Mandates that the reconciliation process is described within the operationalization document of each report.
3. Requires the Bank to document significant changes that occur after or during the data reconciliation.
4. Requires reporting units to document the report production processes in process manuals that adhere to the RRF requirements', N'Business units with responsibilities under RDARR do not perform any process for data reconciliation to test data accuracy and integrity between reports and source data.', N'The Bank has not established a Risk and Finance Reporting Framework outlining a formalised reconciliation process between reports and source data. 
Nevertheless, business units with responsibilities under BCBS 239 perform manual data reconciliation processes to test data accuracy and integrity between reports and source data, before final report generation. However, these processes are not clearly documented. ', N'The Bank has established a Risk and Finance Reporting Framework that meets at least 2 out of 4 conditions and performs manual data reconciliation controls  to test data accuracy and integrity between reports and source data.', N'The Bank has established a Risk and Finance Reporting Framework that meets all conditions and  the data reconciliation controls to test data accuracy and integrity between reports and source data are automated, where appropriate.', N'Risk & Finance Reporting framework owners', N'1) Risk and Finance Reporting Framework
2) Operationalization Documents
2) Reconciliation controls executed.
', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (26, 26, N'5. Group-wide data quality management and standards', N'Group-wide policies and processes should include the full integration of end-user computing or end-user developed applications, including an overview of such applications, into data quality management policies and processes. ', NULL, N'Accuracy and Integrity | Completeness | Timeliness', N'Page 12 enumeration 4', N'The Bank should:
a) develop and maintain a centralised inventory of end user computing to easily track and assess the usage, and updates of end user computing applications.
b) Formalize and apply a comprehensive policy or set of standards to govern the requirements associated with end user computing applications used in risk data aggregation processes and risk reporting. The policy should establish consistent Guidelines, controls, and practices for the creation, modification, and retirement of end user computing applications, reducing the risk of data breaches, errors, unauthorized accesses and loss of critical information.', N'The Bank has not established a policy or set of standards to govern the requirements associated with end user computing applications.
The Bank has not established a centralised inventory of end user computing', N'The Bank has established a policy or set of standards to govern the requirements associated with end user computing. In addition, the Bank maintains an inventory of EUCs which easily tracks and assesses the usage and updates of end user computing applications but does not cover the full perimeter of EUCs.', N'The Bank has established a policy or set of standards to govern the requirements associated with end user computing. There evidence of large compliance with this policy/set of standards.

In addition, the Bank maintains an inventory of EUCs which easily tracks and assesses the usage, updates of end user computing applications and covers the full perimeter of EUCs.', N'The Bank has established a policy or set of standards to govern the requirements associated with end user computing.

There is evidence of full compliance with the policy/set of standards that governs the requirements associated with end user computing.

In addition, the Bank maintains an inventory of EUCs which easily tracks and assesses the usage, updates of end user computing applications and covers the full perimeter of EUCs.

In addition, all the EUCs-related discrepancies are maintained in specific logs by EUC owners.
', N' EUC Policy and Inventory owner 
', N'1)EUC Policy
2) Access to EUC inventory.
3) Percentage of targeted completion.', N'EUC with registered procedures: (Number of EUCs with registered procedures ÷ Total EUCs) x 100 ', NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (27, 27, N'5. Group-wide data quality management and standards', N'Group-wide policies and processes should include arrangements for any manual workarounds within the scope of application to be documented and subjected to adequate control mechanisms (e.g. the "four eyes principle", rigorous documentation and audit trailing of changes, data overrides and sign-offs) until the data preparation and reporting steps that are determined to have a material impact on data quality are embedded in an audit trailed IT-controlled environment.', NULL, N'Accuracy and Integrity | Completeness | Timeliness', N'Page 12 enumeration 5', N'The Bank has established sound arrangements with regards to the documentation of manual workarounds in accordance with the requirements of a Risk Reporting Framework in order to ensure that adequate control mechanisms (e.g. the "four eyes principle", rigorous documentation and audit trailing of changes, data overrides and sign-offs) until the data preparation and reporting steps that are determined to have a material impact on data quality are embedded in an audit trailed IT-controlled environment.', N'No evidence of audit trail, systems or tools is established for managing manual adjustments for reporting purposes of business units, resulting in absence of track record of change logs history.
No Risk and Finance Reporting Framework is established outlining specific requirements for control mechanisms of manual adjustments in the reporting process within the scope of application.', N'The Bank has established a Risk and Finance Reporting Framework outlining specific requirements for control mechanisms of manual adjustments in the reporting process within the scope of application that should be described in detail, per report, in the corresponding operationalization document.

The Bank has not established nor implemented audit trail, systems or tools for managing manual adjustments in the reporting process of business units, with complete track record of change logs history.
', N'The Bank has established a Risk and Finance Reporting Framework outlining specific requirements for control mechanisms of manual adjustments in the reporting process that adjustments in the reporting process within the scope of application that should be described in detail, per report, in the corresponding operationalization document. In addition, the majority of the operationalization documents, within the scope of application, include adequate provisions for manual workarounds and control mechanisms and tracking of manual adjustments and sign-offs is performed.', N'All conditions are met.', N'1) Risk & Finance Reporting framework owners', N'1) Risk Reporting Framework.
2)  Operationalization documents. 
3) Manual Adjustment performance and sign off evidence.', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (28, 28, N'5. Group-wide data quality management and standards', N'Group-wide policies and processes should include adequate consideration of data quality risks in the internal capital adequacy assessment process (ICAAP) and the internal liquidity adequacy assessment process, as existing data quality issues might lead to an underestimation of risks and should be addressed in the risk quantification by an additional margin of conservatism.', 3, N'Accuracy and Integrity', N'Page 12 enumeration 6', N'The Bank has developed policies and processes which ensure:
i) the proper identification and assessment of data quality risks within its risk taxonomy and RIMA process 
ii) data quality issues are identified, assessed, and mitigated. 
iii) the measurement and quantification of data quality risks through an additional margin of conservatism that should be applied to risk quantification to account for potential underestimation of risks due to data quality issues for Pillar I and Pillar II models (where applicable).', N'The Bank has not established policies or processes to ensure adequate consideration of material data quality risks in ICAAP and ILAAP risk quantification, including where such risks may lead to an underestimation of risk.', N'The Bank has established some policies, processes or practices to consider material data quality risks in ICAAP and/or ILAAP risk quantification. However, the approach is not yet sufficiently formalised, comprehensive or consistently applied to ensure that potential risk underestimation is adequately addressed through an additional Margin of Conservatism where relevant.', N'The Bank has established policies and processes to consider material data quality risks in ICAAP and ILAAP risk quantification, including an assessment and inclusion—where applicable— of an additional Margin of Conservatism (MoC) where such risks might lead to risk underestimation. This approach is embedded and evidenced across the majority of relevant areas where the application of MoC has been assessed, while in limited instances, the assessment and inclusion—where applicable—of an additional Margin of Conservatism (MoC) remain pending.', N'The Bank has established policies and processes to consider material data quality risks in ICAAP and ILAAP risk quantification, including an assessment and inclusion—where applicable— of an additional Margin of Conservatism (MoC) where such risks might lead to risk underestimation.

This approach is assessed and integrated throughout all relevant areas of the ICAAP and ILAAP reports, while in areas where no MoC is applied, as a result of relevant assessment, sufficient justification from the respective area owner is provided.', N'ICAAP & ILAAP Coordinator', N'Documentation of adequate consideration of data quality risks in ICAAP & ILAAP ', N'Issues on Material Models: (Number of material models with no significant issues÷ Total material models) x 100', N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (29, 29, N'6. Timeliness of internal risk reporting', N'The frequency of internal risk reporting should match how quickly risk figures can change—more volatile or dynamic risks require more frequent reporting. ICAAP outcomes should be reported to the management body at least quarterly, but institutions with greater size, complexity, or risk exposure may need more frequent updates to support timely decisions. Economic risk measures tend to fluctuate more than normative ones and therefore generally require more frequent reporting', 10, N'Frequency', N'Page 12. Paragraph: The frequency of internal risk reporting […] generally requiring higher reporting frequencies.', N'The Bank has established an Overarching Risk Reporting Framework which ensures the following:
1. The frequency of each material report must be in line with reporting needs and appropriately justified by report owners
2. A feedback procedure is in place for report recipients ensuring the appropriateness of frequency of material reports.', N'No information about the reporting frequency per material internal report is either not availbale or inaccurate in the Bank''s report inventory, while the frequency of each material internal report is not justified by report owners.', N'Reporting frequency information is available per material internal report and has been appropriately justified by all material internal report owners, in the Bank''s report inventory, in line with reporting needs.', N'The Bank has established a Risk and Finance Reporting Framework including requirements relating to the BCBS 239 Frequency principle. There is evidence of an established feedback procedure from BoD and Senior Management regarding the appropriateness of frequency of internal material reports, however the process is performed on ad-hoc basis and not regularly.', N'The Bank has established a Risk and Finance Reporting Framework including explicit requirements relating to the BCBS 239 Frequency principle.
There is an established mechanism in place to receive regular feedback from material reports recipients (BoD & SM) and appropriately implement any recommendations regarding the subject.', N'1) Risk & Finance Reporting framework owners
2) Risk & Finance Data Owners', N'1) Reporting Repository. 
2) Evidence of feedback from BoD and Senior Management', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (30, 30, N'6. Timeliness of internal risk reporting', N'The ECB expects an institution to ensure that the combination of reporting frequency and production time is calibrated in such a manner as to allow for timely reactions to changes in its risk situation, thereby complying with its set of internal risk appetite indicators (metrics and limits). For internal risk reports in normal situations, it is generally understood that institutions will not be able to react to changes in a timely manner if a monthly or quarterly risk report needs more than 20 working days to produce. The production time is dependent on the materiality and volatility of the key risk indicators to be reported.', 10, N'Frequency', N'Pages 12-13. Paragraph: The ECB expects an institution […] key risk indicators to be reported.', N'The institution captures in its Risk Reporting Framework and ensures that monthly and quarterly material internal risk reports are generally produced in less than 20 working days.', N'There is evidence of non-compliance since production time for the majority of monthly and quarterly internal material reports is considerably longer than 20 working days.', N'There is evidence of partial compliance since production time for the majority of monthly and quarterly internal material reports meets the 20 working days target, as set by the RDARR Guide.', N'The Bank has established a Risk and Finance Reporting Framework that captures the target of 20 working days regarding the production time of internal risk reports, in line with the expectation of the RDARR Guide. Production time for the vast majority of monthly and quarterly internal material reports meets the 20 working days target, as set by the RDARR Guide. There is evidence of largely compliance.
', N'The Bank has established a Risk and Finance Reporting Framework that captures the target of 20 working days regarding the production time of internal risk reports, in line with the expectation of the RDARR Guide. In addition, the Bank records and monitors the production time of internal material reports in the report inventory, while there is evidence of full compliance with the target production time of 20 working days, as set in the RDARR Guide.', N'Risk & Finance Data Owners', N'Risk and Finance Reporting Framework. Reporting Repository. Delivery times on selected sample of reports.', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (31, 31, N'6. Timeliness of internal risk reporting', N'Institutions must ensure strong RDARR capabilities not only in normal conditions but also during stress or crisis situations. They should be able to quickly adapt to unexpected events and new reporting requirements, producing granular, ad hoc risk data at both entity and group level. Even under stress, timely risk reporting should not be hindered by fragmented IT systems or heavy manual data‑aggregation processes  ', 6, N'Adaptability', N'Page 13. Paragraph: In addition to sound reporting capabilities in normal situations, […] even in stress situations.', N'To ensure the implementation of effective RDARR capabilities, the institution:
1. Defines requirements relating to the BCBS 239 Adaptability principle within its Risk Reporting Framework, under both normal and stress situations.
2. Defines adaptability requirements within the Risk Reporting Framework based on which the process manuals should include:
  - Capabilities for data customization to users’ needs to drill down as needed, and to produce quick summary reports;
  - Capabilities to incorporate new developments on the organization of the business and/or external factors that influence the bank’s risk profile; and
  - Capabilities to incorporate changes in the regulatory framework
3. Ensures that timely reporting remains unhampered by issues such as a large amount of manual aggregation, even in stress situations.', N'No reporting requirements relating to the BCBS 239 Adaptability principle are documented in the Bank''s policies. No established Risk and Finance Reporting Framework that describes requirements concerning the BCBS 239 Adaptability principle.
', N'There is an established Risk and Finance Reporting Framework that includes requirements relating to the BCBS 239 Adaptability principle. There is no sufficient evidence of compliance in the operationalization/process manuals of the material reports.', N'There is an established Risk and Finance Reporting Framework that includes  requirements relating to the BCBS 239 Adaptability principle. There is evidence of substantial compliance  in the operationalization/process manuals of the material reports and evidence of their implementation in limited stress situations.', N'There is an established Risk and Finance Reporting Framework that includes  requirements relating to the BCBS 239 Adaptability principle. There is evidence of full compliance  in the operationalization/process manuals of the material reports and evidence of their implementation in sufficient stress situations.', N'1) Risk & Finance Reporting framework owners
2) Risk & Finance Data Owners', N'1) Risk and Finance Reporting Framework. 
2) Reporting Repository.
3) Reports Operationalization manuals. 
4) Examples of implementation in stress reporting in ad hoc situations.
5) Fire drill exercices performed (if any)', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (32, 32, N'7. Effective implementation programmes', N'Institutions that do not yet follow the best practices that are described in the BCBS 239 principles should put implementation measures in place accordingly. 

An implementation programme should cover any gaps and address any weaknesses identified through internal or external reviews, including OSIs and off-site reviews by ECB Banking Supervision. 

The programmes should be supported by adequate project management governance, including measures and metrics to control project execution risks, and adequate material, financial and human resources. 

The implementation plans should clearly define remedial actions, targets, milestones, roles, responsibilities and, if applicable, intermediate actions to mitigate weaknesses that require a longer implementation time to be fully addressed. Implementation activities should consider their potential effect on (i) internal models, (ii) interactions and interdependencies of risk data aggregation with the integration of financial reporting frameworks, and (iii) overall business and ICT strategies.

 The implementation programmes should be ambitious yet feasible. Periodical reporting on the progress of the programmes, including analysis of impediments, delays and other factors, should be in place.', NULL, N'Governance | Data Architecture & IT Infrastructure', N'Page 13. Institutions that do not yet follow the best practices […] delays and other factors, should be in place.', N'The Bank has designed a comprehensive and realistic RDARR Compliance programme which encompasses, but is not limited to, the following:
1. Identification of potential gaps with regards to RDARR Compliance
2. A catalogue of BCBS 239 improvement initiatives (projects).
3. A roadmap and prioritization matrix for the improvement initiatives, with detailed time lines of implementation and well assigned roles and responsibilities.
4. Adequate project management governance which includes the monitoring of metrics to control and mitigate project execution risks
5. Periodical reporting on the progress of the programmes, including analysis of impediments, delays and other factors, should be in place.
6. Implementation activities should consider their potential effect on: 
i. internal models
ii. interactions and interdependencies of risk data aggregation with the integration of financial reporting frameworks
iii. overall business and ICT strategies.', N'There is no established BCBS 239 compliance program.', N'To achieve the required level of compliance, at least 2 conditions out of 6 conditions must be met.', N'To achieve the required level of compliance, at least 4 conditions out of 6 conditions must be met including at least condition 1. ', N'To achieve the required level of compliance, all conditions must be met.', N'Data Governance Unit', N'1) Implementation program Governance ,
2)  Scope
3)  Gap analysis
4)  Monitoring through Committees'' meeting minutes.', NULL, NULL);
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (33, 33, N'8. Other expectations from BCBS 239 Paper', N'Risk management reports must be accurate and precise so that senior management can confidently use them for critical decisions. To ensure this accuracy, banks should reconcile key reports with other data, apply automated and manual validation checks using documented rules, and have processes to detect and report data errors. Supervisors expect banks to treat accuracy similarly to accounting materiality—meaning any omission or error that could affect decisions is significant—and to justify their accuracy and precision requirements through testing, validation, and reconciliation results', 7, N'Accuracy', N'BCBS 239 Paper - Paragraph 52, 53, 56', N'To ensure the accuracy, key reports should:
(a) establish requirements and processes for reconciling the key reports with other risk data.
(b) implement the requirements of Risk & Finance Reporting Framework for accuracy, particularly with regard to reconciliation checks (both automated and manual checks). These checks should include an inventory of validation rules that are applied to quantitative information.
(c) integrate procedures for identifying, reporting and explaining data errors or weaknesses in data integrity via exceptions reports (e.g., regarding factors for timeliness and frequency).', N'There are no established requirements that ensure the accuracy of the marerial reports.', N'There are established requirements in the Risk & Finance Reporting Framework, that ensure the accuracy of the marerial reports. There is evidence of partial compliance.', N'There are established requirements in the Risk & Finance Reporting Framework, that ensure the accuracy of the marerial reports. There is evidence of substantial compliance.', N'There are established requirements in the Risk & Finance Reporting Framework, that ensure the accuracy of the marerial reports. There is evidence of full compliance.', N'Risk & Finance Data Owners', N'1) Reconciliation Checks. 
2) Validation rules. 
3) Exception Reports.', N'Critical Reports submitted without errors: (Number of error-free critical reports ÷ Total critical reports submitted for a certain period) x 100', N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (34, 34, N'8. Other expectations from BCBS 239 Paper', N'Approximations—such as model outputs, scenario analyses, and stress‑testing results—are a normal and essential part of risk reporting. Even though they differ from standard reporting, banks must still apply sound reporting principles and set clear expectations for the reliability of these approximations (e.g., accuracy, timeliness). This ensures that management can confidently use them for risk‑related decisions. These expectations extend not only to the approximations themselves but also to the underlying data used to produce them', 7, N'Accuracy', N'BCBS 239 Paper - Paragraph 54', N'The bank should establish in its Risk & Finance Reporting Framework requirements for the reliability of approximations (accuracy, timeliness, etc.) to ensure that management can rely with confidence on the information to make critical decisions about risk. This includes principles regarding data used to drive these approximations.', N'No requirements for approximations made in material risk reports are captured in the Risk & Finance Reporting Framework.', N'Requirements for approximations made in material risk reports are captured in the Risk & Finance Reporting Framework. There is evidence of partial compliance.', N'Requirements for approximations made in material risk reports are captured in the Risk & Finance Reporting Framework. There is evidence of substantial compliance.', N'Requirements for approximations made in material risk reports are captured in the Risk & Finance Reporting Framework. There is evidence of full complaince.', N'1) Risk & Finance Reporting framework owners
2) Risk & Finance Data Owners', N'1) Operationalisation Document
2) Supporting analysis describing the approximations made', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (35, 35, N'8. Other expectations from BCBS 239 Paper', N'Supervisors expect that a bank’s senior management should establish accuracy and precision requirements for both regular and stress/crisis reporting, including critical position and exposure information. These requirements should reflect the criticality of decisions that will be based on this information.', 7, N'Accuracy', N'BCBS 239 Paper - Paragraph 55', N'The Group should establish minimum accuracy and precision requirements for both regular and stress/crisis reporting, as well as controls for reporting in period of stress or crisis set by the Senior Management specifying the expected levels. These requirements should reflect the criticality of decisions based on this information, for stress or crisis conditions. ', N'No reporting requirements for accuracy and precision are established in the Group''s Risk & Finance Reporting Framework.', N'Reporting requirements for accuracy and precision are established in the Group''s Risk & Finance Reporting Framework.

Reporting requirements for accuracy and precision for regular reporting only are captured in operationalization documents of material reports.

There is evidence of partial compliance.', N'Reporting requirements for accuracy and precision for both regular and stress/crisis reporting are captured also in operationalization documents of material reports.

There is evidence of substantial compliance.', N'Reporting requirements for accuracy and precision for both regular and stress/crisis reporting are captured also in operationalization documents of material reports.

There is evidence of full compliance.', N'1) Risk & Finance Reporting framework owners
2) Risk & Finance Data Owners', N'1) Risk and Finance Reporting Framework
2) Operationalisation Documents
3) Evidence in sample of reports (Upon Request)', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (36, 36, N'8. Other expectations from BCBS 239 Paper', N'Risk reports should highlight emerging concentrations, show how risks relate to limits and risk appetite, and recommend actions when needed. They must also update management on the progress of previously agreed risk‑mitigation measures. Reports should look ahead—using forecasts, scenarios, and stress tests—to help the board and senior management understand how key market developments could affect the bank’s future capital and risk profile, rather than relying only on current or historical data', 8, N'Comprehensiveness', N'BCBS 239 Paper - Paragraph 58, 60', N'Material risk reports should not only identify emerging risk concentrations but also provide information within the context of limits and risk appetite/tolerance. Additionally, these reports should propose recommendations for action when deemed necessary.

Moreover, material risk reports should include the current status of measures that have been agreed upon by the Senior Management to mitigate risks or address specific risk situations. This ensures that the committee is kept informed about the progress and effectiveness of the implemented risk reduction measures.

Forward-looking scenarios are used to forecast the group-wide capital and risk profile. These scenarios are presented to the Management Body and are included in certain key reports. The scenarios provide forward looking assessement for market variables and their effects on the group, and are regularly updated to account for new market developments.', N'The Risk & Finance Reporting Framework does not capture requirements for the comprehensiveness of risk reporting.', N'Reporting requirements for comprehensiveness are established in the Group''s Risk & Finance Reporting Framework.

There is evidence of partial compliance.', N'Reporting requirements for comprehensiveness are established in the Group''s Risk & Finance Reporting Framework.
There is evidence of substantial compliance.', N'Reporting requirements for comprehensiveness are established in the Group''s Risk & Finance Reporting Framework.
There is evidence of full compliance.', N'1) Risk & Finance Reporting framework owners
2) Risk & Finance Data Owners', N'1) Operationalisation Documents
2) Material Reports', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (37, 37, N'8. Other expectations from BCBS 239 Paper', N'Risk management reports must cover exposures and positions across all major risk types (credit, market, liquidity, operational) and their key components. They should also include risk‑related metrics such as regulatory and economic capital. Banks are expected to tailor their reporting to fit their own business models and risk profiles, but supervisors must be satisfied that the chosen coverage, analysis, and level of detail are appropriate, scalable, and comparable across the group.  An aggregated risk report should typically present information such as capital adequacy, regulatory capital, capital and liquidity projections, all major risk categories, stress‑testing results, concentrations across and within risk types, and funding positions and plans', 8, N'Comprehensiveness', N'BCBS 239 Paper - Paragraph 57, 59', N'The material risk reports encompass exposure and position information for all significant risk areas, including credit risk, market risk, liquidity risk, and operational risk. They also include the significant components of these risk areas, such as single name, country, and industry sector for credit risk, as well as material concentrations in key industries, products, or geographies.

Additionally, reporting requirements are tailored to fit the specific business models and risk profiles of the organization. This is important to ensure that the reporting is relevant and useful in identifying and managing risks effectively.', N'There is no established Risk Identification and Materiality Assessment (RIMA) process.', N'Established RIMA process. However, the list of material risk reports does not capture all RIMA material risks and components such as single name, country, and industry sector for credit risk, as well as material concentrations in key industries, products, or geographies.', N'The list of material risk reports does capture all RIMA material risks and components such as single name, country, and industry sector for credit risk, as well as material concentrations in key industries, products, or geographies.', N'Risk reporting is consistent and fits the specific business model and risk profiles of the Bank. 
In addition, there is a mechanism in place to recieve recipients'' feedback and appropriately implement any recommendations regarding the subject.', N'1) Risk & Finance Reporting framework owners
2) Risk & Finance Data Owners', N'1) Risk and Finance Reporting Framework
2) RDARR Framework
3) Operationalisation Documents
4) Feedback from report recipients ', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (38, 38, N'8. Other expectations from BCBS 239 Paper', N'Risk reports should provide the right mix of quantitative data, analysis, interpretation, and qualitative explanation. The level of detail should vary by organizational level—more aggregated, qualitative interpretation is expected higher up in the hierarchy. Reports must be clear, useful, and well‑balanced, offering understandable explanations of data and trends along with any recommended conclusions.', 9, N'Clarity and Usefulness', N'BCBS 239 Paper - Paragraph  62, 68', N'To be effective, material risk reports should be clear and useful. They should maintain an appropriate balance between detailed data, qualitative discussion, explanation, and recommended conclusions. The interpretation and explanations of the data, including observed trends, should be clear and easy to understand.', N'The material report does not consider the Content and Structure requirements outlined in the Risk & Finance Reporting Framework.', N'The material reports consider the Content and Structure requirements outlined in the Risk & Finance Reporting Framework and includes quantitative and qualitative information.

There is evidence of partial compliance.', N'The material reports consider the Content and Structure requirements outlined in the Risk & Finance Reporting Framework while it also maintains an appropriate balance between detailed data, qualitative discussion, explanation, and recommended conclusions.
However, there are active comments from the report recipients regarding the Structure and Content of the report.

There is evidence of substantial compliance.', N'The material reports consider the Content and Structure requirements outlined in the Risk & Finance Reporting Framework while it also maintains an appropriate balance between detailed data, qualitative discussion, explanation, and recommended conclusions.
There are no pending comments deriving from the interaction process with the report recipients regarding the Structure and Content of the report.

There is evidence of full compliance.', N'Risk & Finance Data Owners', N'1)Evidence from report recipient''s feedback process', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (39, 39, N'8. Other expectations from BCBS 239 Paper', N'Risk reporting should be tailored to the different needs of the board, senior management, and other organizational levels. The board must define its own reporting requirements and ensure it receives the information needed to fulfill its governance role and monitor adherence to the bank’s risk appetite. If reports are insufficient, the board should inform senior management and request adjustments in the level, type, or balance of information. Senior management must also set its own reporting needs to effectively manage the bank’s risks. Banks are expected to regularly confirm with all report recipients that the information provided is appropriate in both quality and quantity to support sound governance and decision‑making.', 9, N'Clarity and Usefulness', N'BCBS 239 Paper - Paragraph  63, 64, 65, 66,  69', N'As a recipient of key reports, the Board and Senior Management are responsible for determining their own reporting requirements to meet their obligations to shareholders and other stakeholders. They should ensure that they are requesting and receiving relevant information that will enable them to fulfil their governance mandate regarding the bank and the risks it faces. This enables the Board and Senior Management to ensure that the Bank is operating within its risk tolerance and appetite.

If the material reports do not meet the requirements of the Management Body and do not provide the appropriate level and type of information to set and monitor adherence to the bank''s risk tolerance/appetite, the Board should notify the Senior Management.
The Board should also indicate whether it is receiving the appropriate balance of detail and quantitative versus qualitative information in the material reports.

The Risk & Finance Reporting Framework defines a process for periodically confirming with recipients that the information aggregated and reported in the material reports is clear, useful, relevant, and appropriate in terms of both quantity and quality for the governance and decision-making process. Recipients should certify this on an annual basis to ensure clarity, usefulness, and appropriateness of the frequency of material reports.', N'No established Risk & Finance Reporting Framework or no established process for feedback on clarity & usefulness from Board and Senior Management.
', N'There is an established Risk & Finance Reporting Framework approved by the Board that sets standards for clarity & usefulness.', N'There is an established process for collecting feedback from both the Board and the Senior Management. The process is not performed systematically. ', N'There is an established process involving both the Board and the Senior Management for providing feedback on a regular basis. Any propositions are implemented in an agreed timeframe.', N'1) Risk & Finance Reporting framework owners
2) Risk & Finance Data Owners', N'1) Risk and Finance Reporting Framework
2) RDARR Framework
3) Feedback from report recipients ', NULL, N'Market Risk, Liquidity Risk, IRRBB Risk');
  INSERT INTO dbo.questions (id, item_number, thematic_area, requirement, bcbs_principle_number, bcbs_principle_name, ecb_reference, expectations, score_1_desc, score_2_desc, score_3_desc, score_4_desc, respondents_hint, supportive_material, related_kpis, material_risk) VALUES (40, 40, N'8. Other expectations from BCBS 239 Paper', N'Procedures should be in place to allow for rapid collection and analysis of risk data and timely dissemination of reports to all appropriate recipients. This should be balanced with the need to ensure confidentiality as appropriate.
Supervisors expect a bank to confirm periodically that the relevant recipients receive timely reports.', 11, N'Distribution', N'BCBS 239 Paper - Paragraph 72 & 73', N'Procedures should be established to facilitate the swift collection and analysis of data of key reports to all relevant recipients. It is important to strike a balance between the need for rapid communication and the requirement to maintain confidentiality (e.g. classification of the report, distribution list) as appropriate in line with internal confidentiality protocols.', N'Distribution requirements are not covered in the Risk & Finance Reporting Framework.', N'Provisions for distribution are covered in the Risk & Finance Reporting Framework however there is no sufficient evidence of compliance.', N'Distribution requirements covered in the Risk & Finance Reporting Framework, however there is evidence of substantial compliance.', N'Distribution requirements covered in the Risk & Finance Reporting Framework and there is evidence of full compliance.', N'1) Risk & Finance Reporting framework owners
2) Risk & Finance Data Owners
3) Report Distributors', N'1) Risk and Finance Reporting Framework
2) Operationalisation document
3) Report classification evidence', N'Critical Reports submitted on time: (Number of reports submitted on time ÷ Total critical reports submitted for a certain period) x 100', N'Market Risk, Liquidity Risk, IRRBB Risk');
  SET IDENTITY_INSERT dbo.questions OFF;
END
GO
